# -*- coding: utf-8 -*-import streamlit as stimport pandas as pdimport google.generativeai as genaifrom google.api_core import exceptions  # Rate Limit(429) エラーを確実に捕捉するためfrom docx import Documentfrom PyPDF2 import PdfReaderfrom pptx import Presentationimport ioimport configparserimport osimport signalimport reimport time  # リトライ待機（スリープ）処理のため# --- 1. APIキーの設定 (APIKEY.ini または クラウドのSecretsからハイブリッド取得) ---# ※既存のAPI取得ロジックの構造・変数名を1行も崩さずに、クラウド安全対策を内包させていますdef load_api_key():    # 1. まずローカルの APIKEY.ini を探す    config = configparser.ConfigParser()    file_path = 'APIKEY.ini'    if os.path.exists(file_path):        try:            config.read(file_path, encoding='utf-8-sig')            return config.get('GEMINI', 'API_KEY')        except:            pass                # 2. もしローカルにファイルがなければ、Streamlit Cloudの「Secrets」から安全に取得する    try:        if "GEMINI" in st.secrets and "API_KEY" in st.secrets["GEMINI"]:            return st.secrets["GEMINI"]["API_KEY"]        elif "API_KEY" in st.secrets:            return st.secrets["API_KEY"]    except:        return None            return NoneINI_KEY = load_api_key()EMBEDDED_API_KEY = INI_KEY# --- 2. 各ファイル抽出関数 ---def extract_from_docx(file):    doc = Document(file)    return "\n".join([para.text for para in doc.paragraphs])def extract_from_pdf(file):    reader = PdfReader(file)    return "\n".join([page.extract_text() for page in reader.pages if page.extract_text()])def extract_from_pptx(file):    prs = Presentation(file)    text_runs = []    for slide in prs.slides:        for shape in slide.shapes:            if hasattr(shape, "text"):                text_runs.append(shape.text)    return "\n".join(text_runs)def extract_from_excel(file):    all_sheets = pd.read_excel(file, sheet_name=None)    text_data = []    for sheet_name, df in all_sheets.items():        text_data.append(f"--- シート名: {sheet_name} ---\n{df.to_string(index=False)}")    return "\n".join(text_data)# --- 404エラーを回避しつつ、利用可能なモデル名を安全に取得する関数 ---def get_safe_model_name(api_key):    try:        genai.configure(api_key=api_key)        available_models = [m.name for m in genai.list_models() if 'generateContent' in m.supported_generation_methods]                has_flash = any('gemini-1.5-flash' in m for m in available_models)        target_raw = 'gemini-1.5-flash' if has_flash else (available_models[0] if available_models else 'gemini-1.5-flash')                safe_name = target_raw.replace('models/', '')        return safe_name    except:        return 'gemini-1.5-flash'# --- 3. AI回答生成ロジック (自動リトライ・履歴ウィンドウ削減版) ---def get_ai_roleplay_response(messages, persona, product_docs, api_key):    target_model = get_safe_model_name(api_key)        # トークン爆発を防ぐため、AIに送る「過去の履歴」を最新の6発言（3往復）に限定    recent_messages = [messages[0]] + messages[-5:] if len(messages) > 6 else messages    for attempt in range(5):        try:            genai.configure(api_key=api_key)            model = genai.GenerativeModel(target_model)                        combined_docs = "\n\n".join(product_docs) if product_docs else "追加のマニュアル等のアップロードは現在ありません。標準仕様に基づいて回答してください。"                        history_text = ""            for m in recent_messages:                role_label = "AIアシスタント(あなた)" if m["role"] == "assistant" else "本部担当者(ユーザー)"                history_text += f"{role_label}: {m['content']}\n"            system_prompt = f"""あなたは「預かり資産トータルクエリーサービス」およびBIツール「軽技WEB」に精通した熟練のAIFAQアシスタントです。金融機関の本部担当者（ユーザー）からのシステム操作、データ抽出、クエリ、エラー等に関する質問に対して、正確かつ分かりやすく回答してください。【対象サービス・システム構成情報】・サービス名: {persona['service_name']}・概要: {persona['overview']}・接続構成: {persona['architecture']}【本サービスの特徴】{persona['features']}【アップロードされた各種マニュアル・参考ドキュメント（最優先参照情報）】{combined_docs}【回答の絶対ルール】1. ユーザー（本部担当者）の質問に対し、アップロードされたマニュアルの情報を最優先に参照して回答を構成してください。2. あくまで「預かり資産トータルクエリーサービス」および「軽技WEB」「Fund Organizer」の文脈に沿って回答してください。一般的なIT知識でなく、本サービスの仕様を重視してください。3. 専門的な内容であっても、金融機関の業務担当者がスムーズに作業を進められるよう、具体的な手順や選択すべきクエリ（標準クエリ約200種）など、実務に即した丁寧な表現で回答してください。4. アップロードされた情報だけで判断がつかない不確実な事項については、知ったかぶりをせず、「専門のサポート窓口」へ案内するなどの対応を含めてください。5. AIとしてのメタな発言（例：「以上がマニュアルに基づく回答です」など）は含めず、ユーザーへの親切な回答テキストのみを出力してください。【これまでの会話履歴（※直近の重要な会話のみ抽出）】{history_text}上記のルールと履歴を元に、次につづく「AIアシスタント(あなた)」の丁寧な回答を生成してください。"""            response = model.generate_content(system_prompt)            return response.text        except (exceptions.ResourceExhausted, Exception) as e:            error_msg = str(e)            if "429" in error_msg or isinstance(e, exceptions.ResourceExhausted):                wait_time = (attempt + 1) * 10                time.sleep(wait_time)                continue            return f"【システムエラー】詳細: {error_msg}"                return "【混雑エラー】現在AIへのリクエストが連続しています。無料枠の制限を超過したため、1分ほど待ってから再度送信してください。"# --- 4. 画面構築 (Streamlit UI) ---st.set_page_config(page_title="預かり資産トータルクエリーサービス AIFAQ", layout="wide")st.title("📊 預かり資産トータルクエリーサービス AIFAQシステム")st.markdown("投資信託の実績集計や、BIツール「軽技WEB」、データベース「Fund Organizer」に関する疑問を解消するFAQアプリです。")# --- 5. 固定ペルソナ情報設定 ---current_persona = {    "service_name": "預かり資産トータルクエリーサービス",    "overview": "軽技WEBというBIツールを利用した、投資信託の実績集計などが行える金融機関の本部担当者向けサービス。",    "architecture": "顧客（投資家）の契約情報、取引履歴、残高、損益情報を保管しているデータベース「Fund Organizer」を参照元として、本部担当者のブラウザから「軽技WEB」を利用して接続し、データを取得する。",    "features": "①約200の標準クエリから業務要件に合わせたクエリを選択して実行\n②標準クエリを編集しフレキシブルに加工・保存が可能\n③データ取得結果をCSV/Excel形式で保存が可能\n④スケジュール実行で業務の効率化を実現\n⑤専門の担当者による手厚いサポート"}# --- 6. サイドバー機能 (ファイルロードのみ) ---st.sidebar.header("📁 マニュアル・ドキュメント読込")st.sidebar.markdown("<small>クエリーマニュアル、軽技WEB操作マニュアル等をアップロードしてください</small>", unsafe_allow_html=True)uploaded_files = st.sidebar.file_uploader(    "マニュアル資料 (Word, PDF, PPT, Excel)",     type=["docx", "pdf", "pptx", "xlsx", "xls"],     accept_multiple_files=True,    key="file_uploader")all_extra_text = []if uploaded_files:    for f in uploaded_files:        try:            if f.name.endswith(".docx"): content = extract_from_docx(f)            elif f.name.endswith(".pdf"): content = extract_from_pdf(f)            elif f.name.endswith(".pptx"): content = extract_from_pptx(f)            elif f.name.endswith((".xlsx", ".xls")): content = extract_from_excel(f)            all_extra_text.append(f"--- ファイル名: {f.name} ---\n{content}")            st.sidebar.write(f"✔️ 資料読込済: {f.name}")        except Exception as e:            st.sidebar.error(f"❌ {f.name} の読込失敗")st.sidebar.markdown("---")if st.sidebar.button("🛑 アプリを終了する"):    st.sidebar.warning("システムを終了します。")    os.kill(os.getpid(), signal.SIGINT)# --- 7. セッション状態の初期化 ---if "messages" not in st.session_state:    st.session_state.messages = [{"role": "assistant", "content": "「預かり資産トータルクエリーサービス」AIFAQアプリへようこそ。投資信託の実績集計や軽技WEBの操作、標準クエリの活用方法について何でもご質問ください。"}]# --- 8. メインエリアのチャットレイアウト ---st.info(f"💡 マニュアルを読み込ませる場合は、左側のサイドバーからファイルをアップロードしてください。")for m in st.session_state.messages:    role = "assistant" if m["role"] == "assistant" else "user"    avatar = "🤖" if role == "assistant" else "💼"    with st.chat_message(role, avatar=avatar):        st.markdown(m["content"])if prompt := st.chat_input("クエリーサービスの質問内容を入力してください（例：スケジュール実行の方法は？等）"):    st.session_state.messages.append({"role": "user", "content": prompt})    with st.chat_message("user", avatar="💼"):        st.markdown(prompt)    with st.chat_message("assistant", avatar="🤖"):        with st.spinner("該当する情報を確認して回答を作成中..."):            res = get_ai_roleplay_response(                st.session_state.messages,                 current_persona,                 all_extra_text,                 EMBEDDED_API_KEY            )        st.markdown(res)            st.session_state.messages.append({"role": "assistant", "content": res})    st.rerun()